#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(string s) {
        int i = 0, n = s.size();
        // skip leading whitespaces
        while (i < n && isspace(static_cast<unsigned char>(s[i]))) i++;
        // sign
        int sign = 1;
        if (i < n && (s[i] == '+' || s[i] == '-')) {
            if (s[i] == '-') sign = -1;
            i++;
        }
        long long val = 0;
        while (i < n && isdigit(static_cast<unsigned char>(s[i]))) {
            int digit = s[i] - '0';
            if (val > (LLONG_MAX - digit) / 10) { // overflow detection
                return sign == -1 ? INT_MIN : INT_MAX;
            }
            val = val * 10 + digit;
            i++;
        }
        val *= sign;
        if (val < INT_MIN) return INT_MIN;
        if (val > INT_MAX) return INT_MAX;
        return static_cast<int>(val);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    // consume the newline after the integer
    cin.ignore(numeric_limits<streamsize>::max(), '\n');
    getline(cin, s);
    // s may be shorter than n if trailing spaces are trimmed by getline, but problem guarantees exact length
    Solution sol;
    int ans = sol.solve(s);
    cout << ans << "\n";
    return 0;
}
